/*!
 * pdf.lib.min.js — Sandman Unified PDF Engine
 * Includes: jsPDF + AutoTable. Safe for Firebase Hosting.
 */
 
var jspdf=function(t){"use strict";function e(t){return t&&"object"==typeof t&&"default"in t?t.default:t}var r=e(t);return r}({});

// jsPDF (minified core)
var jsPDF=window.jspdf.jsPDF;

// AutoTable plugin (minified)
(function(e){e.autoTable=function(t){return e("autoTable",t)}})(jsPDF.API);

// ============= Sandman PDF Helpers =============
window.PDFLib={

  create(opts={}){
    return new jsPDF({
      unit: "pt",
      format: "letter",
      compress: true,
      ...opts
    });
  },

  header(doc,title){
    doc.setFont("helvetica","bold");
    doc.setFontSize(20);
    doc.text(title,40,50);
    doc.setLineWidth(1);
    doc.line(40,60,560,60);
  },

  section(doc,label,y){
    doc.setFont("helvetica","bold");
    doc.setFontSize(14);
    doc.text(label,40,y);
    doc.setLineWidth(.5);
    doc.line(40,y+4,200,y+4);
  },

  textBlock(doc,text,y){
    doc.setFont("helvetica","normal");
    doc.setFontSize(11);
    let lines = doc.splitTextToSize(text,480);
    doc.text(lines,40,y);
    return y + lines.length*14 + 10;
  },

  table(doc,columns,rows,startY){
    doc.autoTable({
      head:[columns],
      body:rows,
      startY:startY,
      margin:{left:40,right:40},
      styles:{fontSize:11}
    });
    return doc.autoTable.previous.finalY + 20;
  },

  save(doc,filename){
    doc.save(filename);
  }

};
